pure fn remove_duplicates(items: [Number]) -> [Number] {
    seen = []
    result = []
    for item in items {
        found = false
        for s in seen {
            if s == item { found = true }
        }
        if not found {
            seen = append(seen, item)
            result = append(result, item)
        }
    }
    return result
}
