pure fn count_char_freq(text: Text) -> Text {
    chars = split(text, "")
    freq_map = []
    seen = []
    for c in chars {
        if c not in seen {
            seen = append(seen, c)
            count = 0
            for ch in chars {
                if ch == c { count = count + 1 }
            }
            freq_map = append(freq_map, join([c, ":", to_text(count)], ""))
        }
    }
    return join(freq_map, ", ")
}
entry main(x: Text) { return count_char_freq("mississippi") }

