pure fn fibonacci(n: Number) -> [Number] {
    if n <= 0 { return [] }
    if n == 1 { return [0] }
    if n == 2 { return [0, 1] }
    result = [0, 1]
    for i in range(2, n) {
        prev = get(result, i - 1)
        prev_prev = get(result, i - 2)
        next = prev + prev_prev
        result = append(result, next)
    }
    return result
}
