pure fn parse_date(date_str: Text) -> [Number] {
    parts = split(date_str, "-")
    year = to_number(get(parts, 0))
    month = to_number(get(parts, 1))
    day = to_number(get(parts, 2))
    return [year, month, day]
}

pure fn days_in_month(month: Number, year: Number) -> Number {
    if month in [1, 3, 5, 7, 8, 10, 12] { return 31 }
    if month in [4, 6, 9, 11] { return 30 }
    is_leap = year % 4 == 0 and (year % 100 != 0 or year % 400 == 0)
    if is_leap { return 29 }
    return 28
}

pure fn days_between(date1: [Number], date2: [Number]) -> Number {
    y1 = get(date1, 0)
    m1 = get(date1, 1)
    d1 = get(date1, 2)
    y2 = get(date2, 0)
    m2 = get(date2, 1)
    d2 = get(date2, 2)

    total_days = 0

    for y in range(y1, y2) {
        if y % 4 == 0 and (y % 100 != 0 or y % 400 == 0) {
            total_days = total_days + 366
        } else {
            total_days = total_days + 365
        }
    }

    for m in range(1, m1) {
        total_days = total_days - days_in_month(m, y1)
    }
    total_days = total_days - d1

    for m in range(1, m2) {
        total_days = total_days + days_in_month(m, y2)
    }
    total_days = total_days + d2

    return total_days
}

