    for c in chars {
        found = false
        for i in range(0, length(freq_strings)) {
            pair = get(freq_strings, i)
            if starts_with(pair, c) {
                found = true
            }
        }
        if not found {
            count = 0
            for ch in chars {
                if ch == c { count = count + 1 }
            }
            freq_strings = append(freq_strings, join([c, ":", to_text(count)], ""))
        }
    }
    return freq_strings
}

