pure fn mean(nums: [Number]) -> Number {
    total = 0
    for n in nums { total = total + n }
    return total / length(nums)
}

pure fn variance(nums: [Number]) -> Number {
    avg = mean(nums)
    sum_sq_diff = 0
    for n in nums {
        diff = n - avg
        sum_sq_diff = sum_sq_diff + pow(diff, 2)
    }
    return sum_sq_diff / length(nums)
}

pure fn std_dev(nums: [Number]) -> Number {
    return sqrt(variance(nums))
}

intent explain_variability(std: Number, data_range: Text) -> Text {
