    lat_text = get(parts, 1)
    result = to_number(lat_text)
    if is_error(result) { return 0 }
    return unwrap(result)
}

pure fn compare_by_latitude(a: Text, b: Text) -> Number {
    lat_a = get_latitude(a)
    lat_b = get_latitude(b)
    if lat_a < lat_b { return -1 }
    if lat_a > lat_b { return 1 }
    return 0
}

pure fn sort_pairs(pairs: [Text]) -> [Text] {
    n = length(pairs)
    sorted = pairs
    for i in range(0, n) {
        for j in range(0, n - 1) {
            a = get(sorted, j)
            b = get(sorted, j + 1)
            if compare_by_latitude(a, b) > 0 {
                temp_list = []
                for k in range(0, length(sorted)) {
                    if k == j { temp_list = append(temp_list, b) }
                    else if k == j + 1 { temp_list = append(temp_list, a) }
                    else { temp_list = append(temp_list, get(sorted, k)) }
                }
                sorted = temp_list
            }
        }
    }
    return sorted
}

intent describe_pattern(sorted_pairs: Text) -> Text {
