    }
    sorted = sort_pairs(pairs)
    sorted_text = join(sorted, ", ")
    description = describe_pattern(sorted_text)
    return join([sorted_text, " - ", description], "")
}

pure fn fibonacci(n: Number) -> [Number] {
    if n <= 0 { return [] }
    if n == 1 { return [0] }
    if n == 2 { return [0, 1] }

    seq = [0, 1]
    for i in range(2, n) {
        prev = get(seq, i - 1)
        prev_prev = get(seq, i - 2)
        seq = append(seq, prev + prev_prev)
    }
    return seq
}

