pure fn remove_stop_words(text: Text) -> Text {
    stop_words = ["the", "a", "an", "is", "in", "on", "at", "to"]
    words = split(lower(text), " ")
    filtered = []
    for word in words {
        if word not in stop_words {
            filtered = append(filtered, word)
        }
    }
    return join(filtered, " ")
}

